/**
 * Provides a utility function to determine whether a graphic's origin is a [LinkChartGraphicOrigin](https://developers.arcgis.com/javascript/latest/references/core/graphic/LinkChartGraphicOrigin/).
 *
 * @since 5.0
 * @example
 * // Use hitTest() to get a graphic, then check whether it originated from a LinkChartLayer.
 * view.hitTest(screenPoint).then((response) => {
 *   const graphic = response.results[0]?.graphic;
 *   if (!graphic) {
 *     return;
 *   }
 *   if (isLinkChartGraphicOrigin(graphic.origin)) {
 *     // hitTest returned a graphic from a LinkChartLayer.
 *     // Use this info for your processing logic.
 *   } else {
 *     console.log("graphic's origin is NOT a LinkChartLayer");
 *   }
 * });
 */
import type GraphicOrigin from "./GraphicOrigin.js";
import type LinkChartGraphicOrigin from "./LinkChartGraphicOrigin.js";

/**
 * Utility function that determines whether a graphic’s origin is a [LinkChartGraphicOrigin](https://developers.arcgis.com/javascript/latest/references/core/graphic/LinkChartGraphicOrigin/).
 *
 * @param origin - The graphic origin to check.
 * @returns Returns `true` if the graphic origin is of type [LinkChartGraphicOrigin](https://developers.arcgis.com/javascript/latest/references/core/graphic/LinkChartGraphicOrigin/), `false` otherwise.
 */
export function isLinkChartGraphicOrigin(origin: GraphicOrigin | null | undefined): origin is LinkChartGraphicOrigin;